	var taskTableName = 'x_153465_discovert_route_task_instance';

		// STRY0141856
		var api_task = new api_tasker_task();

		// STRY0136617
		data.chatEnabled = new tasking_System_Settings_Scripts().isChatEnabledForUser();

    // moved back to the top.  Since this is async, there is no reason to set any values on data
    if (!input) // asynch load list
        return;
    // STRY0121807
    var taskWidgetIconsAndMessage = new TaskerWidgetIconsAndMessages('tasker_portal_board_with_filter');
    data.settings = taskWidgetIconsAndMessage.loadDefaultsAndSettings($sp);

    if (!input.userDefaultMenuTitle) {
        // DFCT0011087
        data.userDefaultMenuTitle = data.settings.userDefaultMainFilter.diplayValue;
        data.tasker_filter_id = data.settings.userDefaultMainFilter.value;
    } else {
        // DFCT0011087
        data.userDefaultMenuTitle = input.userDefaultMenuTitle;
        data.tasker_filter_id = input.tasker_filter_id;
    }
    data.userID = gs.getUserID();
    // STRY0101803 - load user preferences object for use when opening forms
    // only load this one time
    var tsss = new x_153465_discovert.tasking_System_Settings_Scripts();
    var OUsWhereIamAMember = tsss.getOUsWhereIamAMember();
    // DFCT0010732
    var OUsWhereIamAMemberAdmin = tsss.getMyOUMemberAdmins();
    // DFCT0010709 - when user cleared the filter using breadcrumb, the data.filter would be blank.
    //               when the filter was blank, it would reload the filter from the Option Copy call below resetting the fitler to the value passed in the options
    //               this prevented the user from completely clearing the filter
    //               a new variable was added in the client script when the filter is changed from the breadcrumb
    //               this variable is checked in the if statement below to delete the filter from optionis instead of resetting to the filter passed in options
    if (input.breadcrumb_change == true) {
        data.filter = input.filter;
        options.filter = input.filter;
    }

    if (input && input.getURL == true) {
        var oUserPref = new x_153465_discovert.tasker_User_Form_Preferences();
        // DFCT0010669
        var userPreferences = oUserPref.loadMyFormPreferences();
        // if just getting the URL, then get URL and return
        var url_Properties = oUserPref.get_URL_Properties_for_Task_Based_on_Prefrences(input.sys_id, input.view);
        data.sys_id = input.sys_id;
        data.pageId = url_Properties.pageId;
        data.pageTable = url_Properties.pageTable;
        data.view = url_Properties.view;
        data.portal_url_ref = url_Properties.portal_url_ref;
        // only call once
        data.getURL = false;
        return;
    }
// TODO - LOOK AT PUTTING IN A WIDGET
var api_ui_component_data = new api_tasker_ui_component_data();	
		if(input && input.getActions==true){
			getActions(input.taskSysId);
			return;
		}

    // 2.7.0 | 2021-06-30 | raj | STRY0101803 Added Open in Platform to open the list with the fitler in platform
    data.hasRoleTaskerUser = gs.hasRole('x_153465_discovert.tasker_user');

    data.msg = {};
    data.msg.sortingByAsc = gs.getMessage("Sorting by ascending");
    data.msg.sortingByDesc = gs.getMessage("Sorting by descending");
    data.popOver = "active";

    // copy to data[name] from input[name] || option[name]
    optCopy(['table', 'p', 'o', 'd', 'filter', 'filterACLs', 'field_list', 'keywords', 'view']);
    optCopy(['relationship_id', 'apply_to', 'apply_to_sys_id', 'window_size']);
    // STRY0101803
    optCopy(['modal_title_field_separator', 'modal_title_fields', 'include_comments', 'DiscoverControllerURL']);

	// 2.8.1 | 2023-04-04 | mmcc | STRY0135723 - Homepage Comments column replaced by Task Comments; added isModal
	data.isModal = (input || {}).isModal || (options || {}).isModal || false;

	// 2.8.5 | 2023-07-07 | mmcc | STRY0137588 - View Comment on Detailed Status
	// added, Script Include TaskWidgetData reads Page instance Additonal Lists for this field to pass via options
	data.responseColumnStyle = (input || {}).responseColumnStyle || (options || {}).responseColumnStyle || 'iconsOnly';

	// 2.8.5 | 2023-07-24 | mmcc | STRY0135715 - Edit privilege for my comments in the All Responses Modal; added
	// Set in Page Instance > Additional options, JSON format; if set to directive then launched modal's HTML loads non-form editor
	// If Additional options, JSON format does not include entry then default to form version
	data.responseEditorControl = (input || {}).responseEditorControl || (options || {}).responseEditorControl || 'form';

	// 2.8.5 | 2023-11-08 | mmcc | DFCT0012275 - Existing use of Duration Directive failing to function; added
	data.showLongDates = (input || {}).showLongDates || (options || {}).showLongDates || 
		$sp.getParameter("showLongDates") || false;

	// 2.8.5 | 2023-11-08 | mmcc | DFCT0012275 - Existing use of Duration Directive failing to function; added
	// 2.8.1 | 2023-04-04 | mmcc | STRY0135723 - Homepage Comments column replaced by Task Comments; added
	_convertToBool(['isModal', 'showLongDates']);

    // DFCT0011087 - changed to use id instead of title
    if (data.tasker_filter_id && (input.initialLoad || input.menuChanged)) {
        data = loadDefaultMenu(data.tasker_filter_id, data);
        // DFCT0010617
        data.initialLoad = false;
        data.menuChanged = false;
    }

    if (!data.table) {
        data.invalid_table = true;
        data.table_label = "";
        return;
    }
    // STRY0101803 - changed how data.fields is loaded to include udpates from the fitler selection
    if (!data.field_list) {
        if (data.view)
            data.field_list = $sp.getListColumns(data.table, data.view);
        else
            data.field_list = $sp.getListColumns(data.table);
    }
    data.fields = data.field_list;
    if (!data.modal_title_fields)
        data.modal_title_fields = '';

    // DFCT0010416 - this is a change from the OOTB form
    //data.view = data.view || 'mobile';

    data.table = data.table || $sp.getValue('table');
    // DFCT0010709 - when user cleared the filter using breadcrumb, the data.filter would be blank.
    //               when the filter was blank, it would reload the filter from the Option Copy call below resetting the fitler to the value passed in the options
    //               this prevented the user from completely clearing the filter
    //               a new variable was added in the client script when the filter is changed from the breadcrumb
    //               this variable is checked in the if statement below to delete the filter from optionis instead of resetting to the filter passed in options
    if (input.breadcrumb_change == true) {
        data.filter = input.filter;
    } else {
        data.filter = data.filter || $sp.getValue('filter') || $sp.getParameter('filter');
    }

    // STRY0101803 -default to true if not set
    if (data.include_comments == undefined)
        data.include_comments = true;

    data.keywords = data.keywords || $sp.getValue('keywords');
    data.p = data.p || $sp.getValue('p') || 1;
    data.p = parseInt(data.p);
    data.o = data.o || $sp.getValue('o') || $sp.getValue('order_by');
    data.d = data.d || $sp.getValue('d') || $sp.getValue('order_direction');
    data.page_index = data.p - 1;
    data.show_new = data.show_new || options.show_new;
    var windowSize = data.window_size || $sp.getValue('maximum_entries') || 20;
    windowSize = parseInt(windowSize);
    if (isNaN(windowSize) || windowSize < 1)
        windowSize = 20;
    data.window_size = windowSize;

    var gr;
    if (gs.getProperty("glide.security.ui.filter") == "true") {
		// STRY0146507 - Certification Support- Placeholder - noted not changing, GlideRecord cloned from OOTB widget
        gr = new GlideRecord(data.table);
        gr.applyRowSecurity();
    } else
        gr = new GlideRecordSecure(data.table);
    if (!gr.isValid()) {
        data.invalid_table = true;
        data.table_label = data.table;
        return;
    }

    data.canCreate = gr.canCreate();
    data.newButtonUnsupported = data.table == "sys_attachment";
    data.table_label = gr.getLabel();
    //data.table_plural = gr.getPlural();
    if (data.filter) {
        if (data.filterACLs)
            gr = $sp.addQueryString(gr, data.filter);
        else
            gr.addEncodedQuery(data.filter);
    }

    if (data.keywords) {
        gr.addQuery('123TEXTQUERY321', data.keywords);
        data.keywords = null;
    }

    data.filter = gr.getEncodedQuery();
    if (data.relationship_id) {
		// STRY0146507 - Certification Support- Placeholder - noted not changing, .get call  cloned from OOTB widget
        var rel = GlideRelationship.get(data.relationship_id);
		// STRY0146507 - Certification Support- Placeholder - noted not changing, GlideRecord cloned from OOTB widget
        var target = new GlideRecord(data.table);
		// STRY0146507 - Certification Support- Placeholder - noted not changing, GlideRecord cloned from OOTB widget
        var applyTo = new GlideRecord(data.apply_to);
		// STRY0146507 - Certification Support- Placeholder - noted not changing, .get call  cloned from OOTB widget
        applyTo.get("sys_id", data.apply_to_sys_id);
        rel.queryWith(applyTo, target); // put the relationship query into target
        gr.addEncodedQuery(target.getEncodedQuery()); // get the query the relationship made for us
    }
    if (data.o) {
        if (data.d == "asc")
            gr.orderBy(data.o);
        else
            gr.orderByDesc(data.o);
    }
    // DFCT0010734 Modern Portal Filter - Sort does NOT work on multiple columns
    data.pfm_filter = gr.getEncodedQuery();

    data.window_start = data.page_index * data.window_size;
    data.window_end = (data.page_index + 1) * data.window_size;
    gr.chooseWindow(data.window_start, data.window_end);

		data.showTableFilterButtons = false;

		// STRY0135722
		if(data.table == "x_153465_discovert_route_task_instance"){
			data.showTableFilterButtons = true;

			// Add new query for All or Top Tasks
			data.tableFilterButtonSelected = "showAll";
			data.countAll = _getCount(gr.getEncodedQuery(), false);
			data.countTop = _getCount(gr.getEncodedQuery(), true);

			if(input && input.tableFilterButtonSelected){
				data.tableFilterButtonSelected = input.tableFilterButtonSelected;
				taskWidgetIconsAndMessage.savePreferenceUserDefaultHomeTableFilter(input.tableFilterButtonSelected);
			} else {
				data.tableFilterButtonSelected = data.settings.userDefaultHomeTableFilter;
			}
			if(data.tableFilterButtonSelected=="topTasks"){
				gr.addNullQuery("parent");
			}
		}

    gr._query();
    data.row_count = gr.getRowCount();
    data.num_pages = Math.ceil(data.row_count / data.window_size);
    data.column_labels = {};
    // STRY0101803
    data.fields_array = data.field_list.split(",").map(function(item) {
        return item.trim();
    });
    data.modal_title_fields_array = [];
    if (data.modal_title_fields + '' != '') {
        data.modal_title_fields_array = data.modal_title_fields.split(",").map(function(item) {
            return item.trim();
        });
    }

    data.modal_title_fields_not_set = gs.getMessage('- Modal Title Fields Not Set');

    // use GlideRecord to get field labels vs. GlideRecordSecure
	// STRY0146507 - Certification Support- Placeholder - noted not changing, GlideRecord cloned from OOTB widget
    var grForLabels = new GlideRecord(data.table);

    for (var i in data.fields_array) {
        var field = data.fields_array[i];
        var ge = grForLabels.getElement(field);

        //---------------------------------------------
        //STRY0071963: Servcienow Server JavaScript error getLabel in object null.
        /*if (ge == null)
				continue;

        data.column_labels[field] = ge.getLabel();
        */
        try {
            if (ge == null)
                continue;

            data.column_labels[field] = ge.getLabel();
        } catch (ex) {
            var message = ex.message;
            gs.error("Tasker error in Tasker Portal Board with Filter widget in field : " + message + " | field: " + field + " | ge: " + ge + " | i :" + i);
        }
        //---------------------------------------------		
    }
    data.popOverData = [];
    data.list = [];
		// STRY0135276 - used to hold all of the user information
		data.usersPhotoInfo = {};
		data.userProfiles = {};
		// STRY0137371
		data.loadedDurationOjbects = {};
		// STRY0141856
		data.loadedAssignementOjbects = {};

    data.popOverRecord = {};
    while (gr.next()) {
        // calculate number of comments
        var numComments = 0;
        // STRY0101803 - allow comments to be hidden
        if (data.include_comments) {
            // STRY0101803, change to use data.table to support any table setup in the filter list or the options
            var stream = $sp.getStream(data.table, gr.getUniqueValue());
            for (var x = 0; x < stream.entries.length; x++) {
                if (stream.entries[x].element == 'comments') {
                    numComments++;
                }
            }
        }
        var record = {};
        // TODO, need to add table check here to support more tables		
        // state does page.		If we leave state, than no field will be badged
        //										If we change to allow a badge field, 
        //										then new field would either need to support the same states 
        //										or we would need a badge coding also
        // need to be able to define title fields and order and separator

        // DFCT0010550 - set the default tooltip template
        data.toolTipTemplate = 'task-info-tooltip-template';
        // need to define what loads in quick view for each table or at least set the title as it is different for task than the title on popup		
        var sys_id = gr.getUniqueValue();
        if (!data.popOverRecord[sys_id]) {
            switch (data.table) {
                case 'x_153465_discovert_route_task_instance':
                    // STRY0101803 set the default hover field for Task if not set, load if set
                    data.hoverField = (data.hoverField != undefined && data.hoverField != '') ? data.hoverField : 'short_description';
                    data.popOverRecord[sys_id] = {
                        'sys_id': gr.getUniqueValue(),
                        'title': gr.getDisplayValue('number') + ' - ' + gr.getDisplayValue('short_description'),
                        // 2.6.0 | 2021-04-06 | mmcc | STRY0097980 - Hover Over Task Name HTML; added u_top_task. as subtasks showed blank Objective
                        // "objective": gr.getDisplayValue('u_objective'),
                        "objective": gr.getDisplayValue('u_top_task.u_objective'),
                        "short_description": gr.getDisplayValue('short_description'),
                        "number": gr.getValue('number'),
                        "state": gr.getDisplayValue('state'),
                        "taskType": gr.getDisplayValue('tasker_type'),
                        "classification": gr.getDisplayValue('classification'),
						// 2.8.1 | 2023-03-15 | mmcc | STRY0136499 - 2.8.1 Set CSS Style for Classification based on Value
						"classificationValue": gr.getValue('classification'),
                        "assignment_group": gr.getDisplayValue('assignment_group'),
                        'status': gr.getDisplayValue('status'),
                        'reviewer': gr.getDisplayValue('u_reviewer'),
                        'numComments': numComments
                    };
                    break;
                case 'x_153465_discovert_tasker_requests':
                    // DFCT0010550
                    if (gr.getDisplayValue('parent') != "") {
						// 2.8.1 | 2023-03-15 | mmcc | STRY0136499 - 2.8.1 Set CSS Style for Classification based on Value, force to a string
						var parentClassificationValue = "" + gr.parent.classification;

                        // STRY0101803 set the default hover field for request if not set, load if set
                        data.hoverField = (data.hoverField != undefined && data.hoverField != '') ? data.hoverField : 'number';
                        data.popOverRecord[sys_id] = {
                            'sys_id': gr.getUniqueValue(),
                            'title': gr.getDisplayValue('number') + ' - ' + gr.getDisplayValue('parent.taskernumber') + ' - ' + gr.getDisplayValue('parent.short_description'),
                            // 2.6.0 | 2021-04-06 | mmcc | STRY0097980 - Hover Over Task Name HTML; added u_top_task. as subtasks showed blank Objective
                            // "objective": gr.getDisplayValue('u_objective'),
                            "objective": gr.getDisplayValue('parent.u_top_task.u_objective'),
                            "short_description": gr.getDisplayValue('parent.short_description'),
                            "number": gr.getValue('number'),
                            "state": gr.getDisplayValue('parent.state'),
                            // TODO, QUESTION, do we use request type here or task type or a combination of both?
                            // "taskType": gr.getDisplayValue('parent.tasker_type'),
                            "taskType": gr.getDisplayValue('parent.tasker_type') + ' - ' + gr.getDisplayValue('u_request_type'),
                            "classification": gr.getDisplayValue('parent.classification'),
							// 2.8.1 | 2023-03-15 | mmcc | STRY0136499 - 2.8.1 Set CSS Style for Classification based on Value; use value to set CSS
							"classificationValue": parentClassificationValue,
                            "assignment_group": gr.getDisplayValue('parent.assignment_group'),
                            'status': gr.getDisplayValue('parent.status'),
                            'reviewer': gr.getDisplayValue('parent.u_reviewer'),
                            'numComments': numComments
                        };
                    }
                    // DFCT0010550
                    if (gr.getDisplayValue('u_ou_parent') != "") {
                        var ou_request_status = gr.getDisplayValue('u_status');
                        var state_converted;
                        switch (ou_request_status) {
                            case 'In progress':
                                state_converted = 'Work in Progress';
                                break;
                            case "Completed":
                                state_converted = 'Completed';
                                break;
                        }
                        // reset to ou request template
                        data.toolTipTemplate = 'ou-request-info-tooltip-template';
                        // STRY0101803 set the default hover field for request if not set, load if set
                        data.hoverField = (data.hoverField != undefined && data.hoverField != '') ? data.hoverField : 'number';
                        data.popOverRecord[sys_id] = {
                            'u_ou_parent': gr.getValue('u_ou_parent'),
                            'sys_id': gr.getUniqueValue(),
                            'title': gr.getDisplayValue('number') + ' - ' + gr.getDisplayValue('u_ou_parent.office_name'),
                            "u_request_type": gr.getDisplayValue('u_request_type'),
                            'state_converted': state_converted,
                            'u_status': ou_request_status,
                            'u_request_comments': gr.getDisplayValue('u_request_comments'),
                            'u_requested': gr.getDisplayValue('u_requested'),
                            'u_responded_by': gr.getDisplayValue('u_responded_by'),
                            'u_response': gr.getDisplayValue('u_response'),
                            'u_response_comments': gr.getDisplayValue('u_response_comments'),
                            'response_comments_html': "<p>" + gr.getDisplayValue('u_response_comments').toString().replace(/(?:\r\n|\r|\n)/g, '</p><p>') + "</p>",
                            'request_comments_html': "<p>" + gr.getDisplayValue('u_request_comments').toString().replace(/(?:\r\n|\r|\n)/g, '</p><p>') + "</p>"
                        };
                    }

                    break;
                case 'x_153465_discovert_tasker_schedule':
					// 2.8.1 | 2023-03-15 | mmcc | STRY0136499 - 2.8.1 Set CSS Style for Classification based on Value, force to a string
					var taskerProcessClassificationValue = "" + gr.tasker_process.classification;

					// 2.8.1 | 2023-03-14 | mmcc | DFCT0011660 - My Scheduled Tasks hover Schedule Name; add logic to set a status
					var scheduleStatus = "";
					if (gr.getDisplayValue('next_run_date') != undefined) {
						scheduleStatus = gr.next_run_date.getLabel() + ' - ' + gr.getDisplayValue('next_run_date');
					}

                    // STRY0101803 set the default hover field for request if not set, load if set
                    data.hoverField = (data.hoverField != undefined && data.hoverField != '') ? data.hoverField : 'u_request_comments';
                    data.popOverRecord[sys_id] = {
                        'sys_id': gr.getUniqueValue(),
                        'title': gr.getDisplayValue('number') + ' - ' + gr.getDisplayValue('name'),
                        // 2.6.0 | 2021-04-06 | mmcc | STRY0097980 - Hover Over Task Name HTML; added u_top_task. as subtasks showed blank Objective
                        // "objective": gr.getDisplayValue('u_objective'),
                        "objective": gr.getDisplayValue('tasker_process.u_objective'),
                        "short_description": gr.getDisplayValue('tasker_process.description'),
                        "number": gr.getValue('number'),
						// 2.8.1 | 2023-03-14 | mmcc | DFCT0011660 - My Scheduled Tasks hover Schedule Name; force the header color CSS
                        // "state": gr.getDisplayValue('tasker_process.schedule_complete_flag'),
						"state": 'dtech-bg-color-whitesmoke',
                        // TODO, QUESTION, do we use request type here or task type or a combination of both?
                        // "taskType": gr.getDisplayValue('parent.tasker_type'),
                        "taskType": gr.getDisplayValue('tasker_process.u_tasker_type'),
                        "classification": gr.getDisplayValue('tasker_process.classification'),
						// 2.8.1 | 2023-03-15 | mmcc | STRY0136499 - 2.8.1 Set CSS Style for Classification based on Value; use value to set CSS
						"classificationValue": taskerProcessClassificationValue,
                        "assignment_group": gr.getDisplayValue('tasker_process.u_restricted_group'),
						// 2.8.1 | 2023-03-14 | mmcc | DFCT0011660 - My Scheduled Tasks hover Schedule Name; add logic to set a status
						'status': scheduleStatus,
                        'reviewer': gr.getDisplayValue('tasker_process.u_reviewer'),
                        'numComments': numComments
                    };
                    break;
            }

        }
        // STRY0101803, use the data.field_list instead of optoins.field_list so it is updated for each filter
        $sp.getRecordElements(record, gr, data.field_list);
				if (gr instanceof GlideRecordSecure) {
					// FilteredGlideRecord doesn't do field-level
					// security, so take care of that here
					for (var f in data.fields_array) {
						var fld = data.fields_array[f];
						if (!gr.isValidField(fld))
							continue;

						if (!gr[fld].canRead()) {
							record[fld].value = null;
							record[fld].display_value = null;
						}
						// STRY0135276 - get Pic for each person into an array
						if(record[fld].type == "reference"){
							var refTable = gr[fld].getReferenceTable();
							if(refTable == "sys_user"){

								// NOTE: to handle OoO indicator we need to set the key for 
								//       task to include task GUID and User GUID
								var user_sys_id = record[fld].value;
								loadUserPhotoInfo(user_sys_id, fld, record);
							} else if(refTable == "x_153465_discovert_discover_office_hierarchy"){
								// STRY0141856
								record[fld].isOffice = true;
							}
						}							
					}
				}

				// STRY0137371
				data.showDTechDuration = false;
				// STRY0141856
				data.showDTechAssignment = false;

        switch (data.table) {
				// 2.8.5 | 2023-09-01 | mmcc | DFCT0012141 - Task Work Item Type of review will not show icons and text; added Tasker table name var
				// Task table
			case taskTableName:
				var task_id = gr.getUniqueValue();
				record.u_servicenow_form_view = gr.getValue("u_servicenow_form_view");										
				record.task_name = gr.getDisplayValue("short_description");
				record.comment_state = gr.getDisplayValue("state");
				record.comment_number = ''; // aka task Number
				record.category = {};
				record.sub_category = {};
				record.tasker_type = {};
				record.state = {};

				record.category.display_value = gr.getDisplayValue('category');
				record.category.value = gr.getValue('category');
				record.sub_category.display_value = gr.getDisplayValue('sub_category');
				record.sub_category.value = gr.getValue('sub_category');
				record.tasker_type.display_value = gr.getDisplayValue('tasker_type');
				record.tasker_type.value = gr.getValue('tasker_type');
				record.state.display_value = gr.getDisplayValue('state');
				record.state.value = gr.getValue('state');

				// STRY0137371
				record.comment_number = gr.getDisplayValue('number'); // aka task Number
				data.showDTechDuration = true;
				// STRY0141856
				data.loadedDurationOjbects[task_id] = api_task.getDurationInformation(task_id);
				data.showDTechAssignment = true;
				data.loadedAssignementOjbects[task_id] = api_task.getAssignmentInformation(task_id);

				// 2.8.1 | 2023-04-19 | mmcc | STRY0135713 - Modal showing all comments when clicking the Response Column;
				// use var's just for directive in case those columns are added as fields
				// 2.8.1 | 2023-04-04 | mmcc | STRY0135723 - Homepage Comments column replaced by Task Comments; response is added via fields
				record.directive_reopen_comments = '';
				record.directive_response_comments = '';
				record.directive_reviewer_comments = '';
				record.directive_rework_comments = '';

				// 2.8.5 | 2023-07-07 | mmcc | STRY0137588 - View Comment on Detailed Status; added
				record.directive_content_comment = '';

				// 2.8.5 | 2023-09-01 | mmcc | DFCT0012141 - Task Work Item Type of review will not show icons and text; added
				record.directive_work_item_type = '';

				record.isResponseCommentsDirectiveShown = false;

				// 2.8.1 | 2023-04-19 | mmcc | STRY0135713 - Modal showing all comments when clicking the Response Column;
				if (gr.getElement('comments_dt').getDisplayValue().length > 0 ||
					gr.getElement('response').getDisplayValue().length > 0 ||
					gr.getElement('reopen_comments').getDisplayValue().length > 0 ||
					gr.getElement('rework_comments').getDisplayValue().length > 0) {
					record.isResponseCommentsDirectiveShown = true;
					// 2.8.1 | 2023-04-04 | mmcc | STRY0135723 - Homepage Comments column replaced by Task Comments
					record.directive_reopen_comments = gr.getElement('reopen_comments').getDisplayValue();
					record.directive_response_comments = gr.getElement('response').getDisplayValue();
					record.directive_reviewer_comments = gr.getElement('comments_dt').getDisplayValue();
					record.directive_rework_comments = gr.getElement('rework_comments').getDisplayValue();
				}

				// 2.8.5 | 2023-09-01 | mmcc | DFCT0012141 - Task Work Item Type of review will not show icons and text; get display value
				record.directive_work_item_type = gr.getElement('work_item_type').getDisplayValue();

				// 2.8.5 | 2023-07-07 | mmcc | STRY0137651 - When to Show Comments on Final Response Tab; added, get returns a string
				// 2.8.5 | 2023-09-01 | mmcc | DFCT0012141 - Task Work Item Type of review will not show icons and text; use the retrieved data
				if (record.directive_work_item_type == 'review_item') {
					record.directive_content_comment = record.directive_reviewer_comments;
				} else {
					record.directive_content_comment = record.directive_response_comments;
				}

				break;
            case 'x_153465_discovert_tasker_requests':
                record.category = {};
                record.sub_category = {};
                record.tasker_type = {};
                record.state = {};
                // STRY0108629
                if (gr.parent) {
                    record.parentType = 'Task';
                    record.category.display_value = gr.getDisplayValue('parent.category');
                    record.category.value = gr.getValue('parent.category');
                    record.sub_category.display_value = gr.getDisplayValue('parent.sub_category');
                    record.sub_category.value = gr.getValue('parent.sub_category');
                    record.tasker_type.display_value = gr.getDisplayValue('parent.tasker_type');
                    record.tasker_type.value = gr.getValue('parent.tasker_type');
                    record.state.display_value = gr.getDisplayValue('parent.state');
                    record.state.value = gr.getValue('parent.state');
										// STRY0135276 - get Pic for each person into an array
										var ownerField = "parent.u_task_requester";
										var taskOwner = record[ownerField];
										if(taskOwner){
											var ownerId = taskOwner.value;
											loadUserPhotoInfo(ownerId, ownerField, record);
										}

                } else {
                    record.parentType = 'Organizational Unit';
                    record.u_ou_parent = gr.getValue('u_ou_parent');
                }
                break;
            default:
                break;
        }
        record.sys_id = gr.getValue('sys_id');
        record.dcu_ref = '';
        // STRY0101803 set the id for the Task page based on the table of the filter
        switch (data.table) {
            case 'x_153465_discovert_route_task_instance':
                record.href_id = gr.getValue('sys_id');
                break;
            case 'x_153465_discovert_tasker_requests':
                if (gr.parent) {
                    record.href_id = gr.getValue('parent');
                } else {
                    // STRY0108629
                    record.href_id = gr.getValue('sys_id');
                    record.dcu_ref = 'u_ou_parent';
                }
                break;
            case 'x_153465_discovert_tasker_schedule':
                record.href_id = gr.getValue('sys_id');
                break;
            default:
                record.href_id = gr.getValue('sys_id');
                break;
        }

        // 2.6.0 | 2021-04-26 | mmcc | STRY0100152 - Add a new boolean property to indicate when to show the tooltip
        record.isTooltipOpened = false;

        data.list.push(record);
    }

    data.enable_filter = (input.enable_filter == true || input.enable_filter == "true" ||
        options.enable_filter == true || options.enable_filter == "true");
    /*
    	var breadcrumbWidgetParams = {
    		table: data.table,
    		query: data.filter,
    		enable_filter: data.enable_filter
    	};

    	data.filterBreadcrumbs // = $sp.getWidget('widget-filter-breadcrumbs', breadcrumbWidgetParams);
    */

// TODO - THIS MIGHT BE BETTER IN A WIDGET
		function getActions(taskSysId){
			data.actions = api_ui_component_data.getContextMenuInformation(api_dtech_common.CONST_DTECH_TASK_TABLE_NAME, taskSysId);
		}

		// STRY0135722
		function _getCount(encodedQuery, topOnly){
			var count = 0;
			var ga_count = new GlideAggregate(data.table);
			ga_count.addEncodedQuery(encodedQuery);
			if(topOnly){
				ga_count.addNullQuery("parent");
			}
			ga_count.addAggregate('COUNT');
			ga_count.query();
			if (ga_count.next()) {
				count = ga_count.getAggregate('COUNT');
			}
			return count;
		}

		// STRY0135276 - get Pic for each person into an array
		function loadUserPhotoInfo(user_sys_id, field, objRec){
			// NOTE: to handle OoO indicator we need to set the key for 
			//       task to include task GUID and User GUID
			objRec[field].isUser = true;
			if(!data.usersPhotoInfo[user_sys_id]){
				// user not in array yet
				var photoInfo = new UserInfoScripts().loadPhotoInfo(user_sys_id);
				data.usersPhotoInfo[user_sys_id] = photoInfo;
				// initialize profile object
				data.userProfiles[user_sys_id] = {};
				data.userProfiles[user_sys_id].sys_id = photoInfo.sys_id;
				data.userProfiles[user_sys_id].photo = photoInfo.photo;
				data.userProfiles[user_sys_id].name = photoInfo.name;
				data.userProfiles[user_sys_id].loaded = false;
			}
		}

    function getFilterMenuHeaderPosition(taskerFilters, menuHeader) {
        var position = -1;

        for (var i = 0; i < taskerFilters.length; i++) {
            if (taskerFilters[i].header == menuHeader) {
                position = i;
                break;
            }
        }

        return position;
    }

    // copy to data from input or options
    function optCopy(names) {
        names.forEach(function(name) {
            data[name] = input[name] || options[name];
        });
    }
    // DFCT0011087 - changed to use id instead of title
    function loadDefaultMenu(filterId, data) {
        var menuFound;
        // DFCT0011087 - changed to use id instead of title
        menuFound = loadFilter(filterId);
        // uddate data object with menu found
        if (menuFound) {
			// 2.8.1 | 2023-03-14 | mmcc | DFCT0011660 - My Scheduled Tasks hover Schedule Namey; added hoverField
			data.hoverField = menuFound.hoverField;
            data.table = menuFound.table;
            data.filter = menuFound.filter;
            data.sp_page_dv = menuFound.view_all_page;
            data.title = menuFound.filter_label;
            data.d = menuFound.d;
            data.o = menuFound.o;
            data.modal_title_field_separator = menuFound.modal_title_field_separator;
            data.modal_title_fields = menuFound.modal_title_fields;
            // STRY0108629
            data.DiscoverControllerURL = menuFound.DiscoverControllerURL;
            data.include_comments = menuFound.include_comments;
            if (menuFound.field_list != undefined && menuFound.field_list != '') {
                data.field_list = menuFound.field_list;
            } else {
                data.field_list = undefined;
            }
        }
        return data;
    }

    // DFCT0011087 - changed to use id instead of title
    function loadFilter(filterId) {
        var filter;
        // get filter from filters table
        // STRY0101803 - had to change to glide record as some users couldn't see the Table field
		// STRY0146507 - Certification Support- Placeholder - noted not changing, Configuration only.  No data read
        var gr_filters = new GlideRecord('x_153465_discovert_tasker_filters');
        // DFCT0011087 - changed to use id instead of title
        if (gr_filters.get(filterId)) {
            // STRY0099083
            var currentFilter = gr_filters.getDisplayValue('u_filter');
            // DFCT0010732
            if (currentFilter.indexOf("OUsWhereIamAMemberAdmin") > 0) {
                currentFilter = currentFilter.replace("OUsWhereIamAMemberAdmin", OUsWhereIamAMemberAdmin);
            }
						// DFCT0011947
            if (currentFilter.indexOf("OUsWhereIamAMember") > 0) {
                currentFilter = currentFilter.replace("OUsWhereIamAMember", OUsWhereIamAMember.join(","));
            }
            // STRY0108629
            var DiscoverControllerURL = gr_filters.getValue('u_discover_controller_url');
            DiscoverControllerURL = DiscoverControllerURL != null ? (DiscoverControllerURL == true) : false;

            // 2.7.0 | 08.06.2021 | mmcc | STRY0106157 - PPM – Modern Portal – New Filter Design
            // Create the filter then push later
            filter = {
                tasker_filter_id: gr_filters.getUniqueValue(),
                table: gr_filters.getDisplayValue('u_table.name'),
                // STRY0101803
                field_list: gr_filters.getDisplayValue('u_field_list') + '',
                modal_title_fields: gr_filters.getDisplayValue('u_modal_title_fields') + '',
                modal_title_field_separator: gr_filters.getDisplayValue('u_modal_title_field_separator') + '',
                // STRY0101803 load the "hover over field" from the filter defnition if set
                hoverField: gr_filters.getDisplayValue('u_hover_field') + '',
                filter_label: gr_filters.getDisplayValue('u_filter_label'),
                filter: currentFilter,
                view_all_page: gr_filters.getDisplayValue('u_view_all_page'),
                // STRY0101803
                // 2.7.0 | 08.06.2021 | mmcc | STRY0106157 - PPM – Modern Portal – New Filter Design
                // include_comments: gr_filters.getDisplayValue('u_include_comments'),
                include_comments: gr_filters.getValue('u_include_comments'),
                // STRY0108629
                DiscoverControllerURL: DiscoverControllerURL,
                o: gr_filters.getDisplayValue('u_order_by'),
                d: gr_filters.getDisplayValue('u_direction')
            };
        }

        return filter;
    }

	// 2.8.1 | 2023-04-04 | mmcc | STRY0135723 - Homepage Comments column replaced by Task Comments; added function _convertToBool(names) {}
	function _convertToBool(names) {
		names.forEach(function(name) {
			data[name] = data[name] == true || data[name] == 'true';
		});
	}	
})($sp, input, data, options, gs);
